import networkx as nx

def traveling_salesman_problem(edge_list, weight='weight', nodes=None, cycle=True, method=None, **kwargs):
    G = nx.DiGraph()
    # Accept edges as (u, v), (u, v, w), or (u, v, attr_dict)
    for edge in edge_list:
        if len(edge) == 2:
            u, v = edge
            G.add_edge(u, v)
        elif len(edge) == 3:
            u, v, data = edge
            if isinstance(data, dict):
                G.add_edge(u, v, **data)
            else:
                G.add_edge(u, v, **{weight: data})
        else:
            raise ValueError("Each edge must be (u, v), (u, v, weight), or (u, v, attr_dict).")

    result = nx.approximation.traveling_salesman_problem(
        G, weight=weight, nodes=nodes, cycle=cycle, method=method, **kwargs
    )
    return result```

